select sum(changeNum) from goldChange 
where userId = #{userId,jdbcType=VARCHAR} 
and 
serverId = #{serverId,jdbcType=VARCHAR}
and
time > #{begin,jdbcType=INTEGER} 
and 
time < #{end,jdbcType=INTEGER} 
and reason = 22;

select sum(changeNum) from goldChange 
where roleId = #{roleId,jdbcType=VARCHAR} 
and reason = 22;

select sum(changeNum) from goldChange 
where roleId = #{roleId,jdbcType=VARCHAR} 
and 
time > #{begin,jdbcType=INTEGER} 
and 
time < #{end,jdbcType=INTEGER} 
and reason = 22;

select userId, sum(changeNum) AS num from goldChange 
where time > #{begin,jdbcType=INTEGER} 
and 
time < #{end,jdbcType=INTEGER} 
and reason = 22 GROUP BY userId ORDER BY num DESC LIMIT 10;

select sum(0-changeNum) from goldChange 
where userId = #{userId,jdbcType=VARCHAR} 
and 
serverId = #{serverId,jdbcType=VARCHAR}
and 
time > #{begin,jdbcType=INTEGER} 
and 
time < #{end,jdbcType=INTEGER} 
and changeNum < 0 and reason != 45 and reason != 157;

select sum(0-changeNum) from goldChange 
where roleId = #{roleId,jdbcType=VARCHAR} 
and 
time > #{begin,jdbcType=INTEGER} 
and 
time < #{end,jdbcType=INTEGER} 
and changeNum < 0;

select roleId,sum(0-changeNum) AS num from goldChange 
where time > #{begin,jdbcType=INTEGER} 
and 
time < #{end,jdbcType=INTEGER} 
and changeNum < 0 and reason != 45 and reason != 157 GROUP BY roleId ORDER BY num DESC LIMIT 10;
